const Q_CHEMISTRY_2010=[{"id": "objective>Chemistry>2010>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject is indicated in the id of the question. In this case, it is 'Chemistry'.</div>", "topic": "CHEMISTRY"}, {"id": "objective>Chemistry>2010>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of a mixture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Common salt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Washing soda</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture is a substance made by combining two or more different materials in such a way that no chemical reaction occurs. A mixture can usually be separated back into its original components. 'Blood' is the correct answer.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>2010>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the percentage by mass of nitrogen in calcium trioxonitrate(V).  <br/> (Ca = 40; N = 14; O = 16)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.5% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.1% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">27.6%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Ca(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = Calcium trioxonitrate (V) <br/> * The RMM of Ca(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  = 40 + 2(14 + 3(16)) <br/>  = 40 + 2(14 + 48) <br/>  = 40 + 2(62) <br/>  = 40 + 124 = 164gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> * The RMM of nitrogen (N(2))  <br/> =2 x RAM of N <br/>  = 2(14) = 28g <br/> ∴ % by mass of nitrogen (N) in Ca(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= (No of atoms of N in Ca(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> x RAM of N)/RMM of Ca(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> x100 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">28<hr size=\"1\" />164</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2800<hr size=\"1\" />164</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">17.1%</td></tr></table></div></div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2010>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The droplets of water observed around a bottle of milk taken out of the refrigerator is due to the fact that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water vapour in the air around the bottle gains some energy from the bottle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature of the milk drops as it loses heat to the surroundings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saturated vapour pressure of the milk is equal to the atmospheric pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water vapour in the air around the bottle loses some of its energy to the bottle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The droplets of water observed around a bottle of milk taken out of the refrigerator is due to condensation. This happens when the water vapour in the air around the bottle loses some of its energy to the cold bottle, condenses and forms water droplets.</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2010>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of a given gas is V cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at PmmHg. What is the new volume of the gas if the pressure is reduced to half at constant temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4V cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2V cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">V/2cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">V cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Boyle's law, the volume of a gas is inversely proportional to its pressure at constant temperature. Therefore, if the pressure is reduced to half, the volume of the gas will double. <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=Pmmhg <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=Vcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=P/2 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=? <br/> P x V=P/2 x V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> PV=PV<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/2 <br/> 2PV=PV<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 2V=V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=2V</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2010>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Moving from left to right across a period, the general rise in the first ionization energy can be attributed to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease in nuclear charge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in nuclear charge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in screening effect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in screening effect</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Moving from left to right across a period, the number of protons in the nucleus (nuclear charge) increases. This increased nuclear charge attracts the electrons more strongly, making it harder to remove an electron and thus increasing the first ionization energy. The screening effect, which is the ability of inner shell electrons to shield outer shell electrons from the nuclear charge, does not significantly change across a period because the added electrons are in the same shell.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2010>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many unpaired electron(s) are there in the nitrogen sub-levels?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen has 7 electrons in all.  <br/> Its electronic configuration is = 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/> So, it has three unpaired electrons in its p-orbitals.  <br/> Note that the p orbital can accommodate a maximum of 6 electrons. <br/> Nitrogen has 5 electrons in its outer shell (2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>). The 2s sublevel is fully filled with 2 electrons, and the 2p sublevel has 3 electrons, each occupying a different 2p orbital. Therefore, there are 3 unpaired electrons in the nitrogen sub-levels.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2010>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stability of the noble gases is due to the fact that they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have no electron in their outermost shells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have duplet or octet electron configurations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">belong to group zero of the Periodic Table</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are volatile in nature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stability of the noble gases is due to their full outer electron shells. They have either a duplet (for Helium) or an octet (for the rest of the noble gases) electron configuration in their outermost shell. This full electron configuration is very stable and results in the noble gases being generally unreactive.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2010>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum number of electrons in the L shell of an atom is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">18 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">32.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To get the maximum number of electrons in a shell we use: 2n<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, where n represents the position of the shell from the nucleus. <br/> k → n = 1 <br/> L → n = 2 <br/> M → n = 3 <br/> N → n = 4 <br/> O → n = 5 <br/> P → n = 6 <br/> Q → n = 7 <br/> For L, we have: 2(2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>) = 2(4) = 8</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2010>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Elements in the same period in the Periodic Table have the same</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">number of shells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">atomic number</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemical properties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physical properties</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elements in the same period in the Periodic Table have the same number of electron shells. A period refers to a horizontal row in the periodic table. Elements are arranged in periods according to the number of electron shells in their atoms, so all elements in a period have the same number of shells.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2010>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The reaction above illustrates</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alpha decay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">artificial transmutation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nuclear fusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nuclear fission</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction illustrates nuclear fusion since two lighter masses join/fuse together to form a heavier one accompanied with the release of energy.  </div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2010>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A noble gas with a high power of fog penetration used in aerodrome beacons is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">krypton </div>", "<div style=\"font-family:Cambria;font-size:17px;\">argon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">neon</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Neon has a high power of fog penetration and hence used in aerodrome beacons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2010>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Permanent hardness of water can be removed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">filtration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding slaked lime</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding caustic soda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Permanent hardness of water is removed by adding caustic soda.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2010>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Substances employed as drying agents are usually</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amphoteric </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hygroscopic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efflorescent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Substances employed as drying agents are usually hygroscopic. These are substances that absorb water from the environment and yet do not change their form. Examples include silica gel, Calcium chloride etc.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : PURE AND IMPURE SUBSTANCES"}, {"id": "objective>Chemistry>2010>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the solubility in mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of 40g of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> dissolved in 100g of water at 120°C.  <br/>  [Cu = 64, S = 32, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.40 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solubility = (number of moles of solution)/(volume of solution)  <br/>  100g of water = 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> =160g/mol  <br/>  Number of moles of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> =  40/160  = 0.25 mol.  <br/>  Solubility = (0.25 mol)/(0.1 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>) = 2.5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2010>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Coffee stains can best be removed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kerosine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">turpentine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a solution of borax in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ammonia solution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coffee stains can best be removed by a solution of borax in water. Borax, or sodium borate, is a natural mineral compound that can break down and dissolve the organic matter and oils that make up most stains, including coffee.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2010>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (II) oxide is considered dangerous if inhaled mainly because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can cause injury to the nervous system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competes with the oxygen in the blood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competes with the carbon (IV) oxide in the blood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can cause lung cancer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (II) oxide, also known as carbon monoxide, is dangerous when inhaled because it binds to hemoglobin in the blood more readily than oxygen does. This reduces the amount of oxygen that can be transported in the blood, leading to hypoxia (lack of oxygen) in tissues and organs.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2010>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The acid that is used to remove rust is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">boric</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrochloric</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trioxonitrate(V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetraoxosulphate(VI)</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Phosphoric acid in the present invention, tartrate, citric acid has played the function of assisting derusting rust-proofing, has strengthened the rust cleaning ability of this product. <br/>  <br/> Hydrochloric acid (which is also called muriatic acid in its diluted form), as well as phosphoric acid and sulfuric acid may be used in rust removal formulas using strong acids. These are mineral acids, and they are highly corrosive, especially in concentrated forms.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2010>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the volume of 0.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> that is neutralized by 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.1 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> NaOH.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equation for the reaction <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2NaOH → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> 1&nbsp &nbsp &nbsp: &nbsp &nbsp &nbsp 2 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 0.5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 0.1 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = Unknown <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.5×V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />0.1×25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 2.5cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2010>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The colour of methyl orange in alkaline medium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yellow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pink</div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">red.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Methyl orange is a pH indicator that changes color depending on the pH of the solution. In an alkaline (basic) medium, methyl orange is yellow.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2010>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following salts is slightly soluble in water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AgCI </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">PbCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is slightly soluble in water among the others.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2010>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">6AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span> + PH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g) </span>+ 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span>→ 6Ag<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span> + 6HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span>  <br/> In the reaction above, the reducing agent is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">PH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">PbNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, PH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is the reducing agent. A reducing agent is a substance that loses electrons in a redox chemical reaction. In this case, PH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> loses hydrogen atoms (which are equivalent to losing electrons) to form H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2010>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature of the compound LiAIH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lithium tetrahydridoaluminate (III)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium tetrahydrido lithium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetrahydrido lithium aluminate (III)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lithium aluminium hydride</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The compound, LiAlH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/> We need to get the oxidation number of aluminium in this compound. <br/> We already know that it is \"Lithium tetra hydrido aluminate. But the question is, it is aluminate what? <br/> +1 + x + 4(-1) = 0 <br/> 1 + x - 4 = 0 <br/> x - 3 = 0 <br/> x = 3 <br/>  <br/> LiAlH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is lithium tetrahydridoaluminate (III)</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2010>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Iron can be protected from corrosion by coating the surface with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gold </div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iron can be protected from corrosion by coating the surface with zinc. This process is known as galvanization. Zinc acts as a sacrificial anode, corroding before the iron does, thus protecting the iron from corrosion.</div>", "topic": "ELECTROLYSIS : CORROSION"}, {"id": "objective>Chemistry>2010>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What quantity of aluminium is deposited when a current of 10A is passed through a solution of an aluminium salt for 1930s?  <br/>  (Al = 27, F = 96,500 Cmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.2 g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.4 g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.2 g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is what happens at the Cathode: <br/> Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span>  + 3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> →  Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> 3F → 27g <br/> Note: 1F = 96500C  <br/> 3F = 96,500 × 3 = 289,500C <br/> It implies that: 289,500 = 27g <br/> Q = It = 10 × 1930 = 19,300C <br/> If 289,500C → 27g <br/> 19300 → x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">193 × 27<hr size=\"1\" />2895</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.8g</td></tr></table></div></div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2010>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following is the entropy change positive?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thermal dissociation of ammonium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reaction between an acid and a base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Addition of concentrated acid to water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dissolution of sodium metal in water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entropy is a measure of the disorder or randomness of a system. The thermal dissociation of ammonium chloride (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl) into ammonia (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) and hydrogen chloride (HCl) results in an increase in entropy because the number of gaseous molecules increases, leading to greater disorder.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2010>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a reaction is exothermic and there is a great disorder, it means that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the reaction is static</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the reaction is in a state of equilibrium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there will be a large increase in free energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there will be a large decrease in free energy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An exothermic reaction is one that releases heat. This means that the energy of the products is less than the energy of the reactants, hence there is a decrease in free energy. The concept of disorder refers to entropy, a measure of the randomness or disorder of a system. A great disorder means high entropy. According to the second law of thermodynamics, for a spontaneous reaction, the total entropy of the universe must increase. Therefore, an exothermic reaction with great disorder is likely to be spontaneous, leading to a large decrease in free energy.</div>", "topic": "ENERGY CHANGES : SPONTANEITY OF REACTIONS"}, {"id": "objective>Chemistry>2010>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the preparation of oxygen by heating KCIO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> in the presence of MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, only moderate heat is needed because the catalyst acts by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lowering the pressure of the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the surface area of the reactant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the rate of the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lowering the energy barrier of the reaction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A catalyst works by providing an alternative reaction pathway with a lower activation energy. This means that it lowers the energy barrier of the reaction, allowing the reaction to proceed more quickly at a given temperature. Therefore, only moderate heat is needed in the presence of a catalyst.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2010>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The graph above demonstrates the effect of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">surface area on the rate of reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">catalyst on the rate of reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure on the rate of reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentration on the rate of reaction.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The graph demonstrates the effect of surface area on the rate of reaction. Note that the powdered marble has a higher chemical kinetics since it has a larger surface area compared to the marble chips. </div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2010>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ↔ 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>; ΔH = -ve  <br/>  What happens to the equilibrium constant of the reaction above if the temperature is increased?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It is unaffected</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It becomes zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It increases</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>+O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ↔ 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>ΔH= -ve   <br/> The equation undergoes exothermic reaction. Increase in temperature doesn't favour the forward reaction, this however decreases it's equilibrium constant. Whereas decrease in the temperature will favour the forward reaction and cause an increase in the equilibrium constant</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2010>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To a solution of an unknown compound,a little dilute tetraoxosulphate(VI) acid was added with some freshly prepared iron(II) tetraoxosulphate(VI) solution. The brown ring observed after the addition of a stream of concentrated tetraoxosulphate (VI) acid confirmed the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CI<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The brown ring test is a qualitative test for the detection of nitrate ions (NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>). In this test, a solution of the compound is treated with iron(II) sulfate and then concentrated sulfuric acid is carefully added. A brown ring at the interface of the two layers indicates the presence of nitrate ions.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2010>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, the gas produced is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NO </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The setup is for the production of NO in the laboratory.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2010>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of this following is used as a rocket fuel?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCI</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rocket fuel needs to be highly reactive and provide a large amount of energy when burned. Nitric acid (HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) is a powerful oxidizing agent and can react with a fuel to produce a large amount of energy, making it suitable for use as a rocket fuel.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : OXYGEN AND SULPHUR"}, {"id": "objective>Chemistry>2010>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, the purpose of <br/> the asbestos is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absorb impurities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">catalyze the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solidify the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dry the gas</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Asbestos in the set up serves to a catalyst in the reaction.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2010>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A constituent common to bronze and solder is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lead </div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bronze and solder both contain tin. Bronze is an alloy of copper and tin, and solder is a low-melting alloy, especially one based on lead and tin or (for higher temperatures) on brass or silver.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2010>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When iron is exposed to moist air, it gradually rusts. This is due to the formation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrated iron(III) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anhydrous iron(III) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anhydrous iron(II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrated iron(II) oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When iron is exposed to moist air, it gradually rusts. This is due to the formation of hydrated iron(III) oxide. Rust is the common name for a very common compound, iron oxide. Iron oxide, the chemical Fe2O3, is common because iron combines very readily with oxygen -- so readily, in fact, that pure iron is only rarely found in nature.</div>", "topic": "ELECTROLYSIS : CORROSION"}, {"id": "objective>Chemistry>2010>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound gives an orange-red colour to a non-luminous flame. This compound is likely to contain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> gives an orange red colour to a non-luminous flame.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2010>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Stainless steel is used for making</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tools</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coins and medals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moving parts of clocks</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stainless steel is used for making tools. Stainless steel is known for its corrosion resistance. It is also known for its strength and its ability to withstand high and low temperatures. Because of these properties, it is used in a wide range of products, including tools.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2010>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The residual solids from the fractional distillation of petroleum are used as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coatings for pipes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials for the cracking process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fuel for driving tractors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fuel for jet engines.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The residual solids from the fractional  distillation of petroleum are used as coatings for pipes.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2010>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The IUPAC nomenclature of the compound above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4-ethyloctane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5-ethyloctane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5-propylheptane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-propylheptane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">4-ethyloctane. <br/>  <br/>  The bond is a single bond (-ane) <br/>  <br/>  The longest continous carbon chain is 8 (Oct) <br/>  <br/>  The only attachment here is ethyl, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>, which is on the fourth carbon atom.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2010>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used as fuel in miners' lamp?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ethanal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethyne, also known as acetylene, is used as fuel in miners' lamps. It burns with a bright flame and is therefore suitable for lighting purposes in mines.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2010>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organic compounds is very soluble in water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH, also known as acetic acid, is very soluble in water. This is because it can form hydrogen bonds with water molecules, which is a key factor in solubility.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2010>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Benzene reacts with hydrogen in the presence of nickel catalyst at 180°C to give</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">xylene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">toluene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclopentane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclohexane.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Benzene reacts with hydrogen in the presence of nickel catalyst at 180°C to give Cyclohexane. <br/>  <img src=\"2010/k41.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2010>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used to hasten the ripening of fruits?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ethene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethyne </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethane.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethene is used in agriculture to hasten the ripening of fruits such as banana, plantain and oranges.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2010>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The final products of the reaction between methane and chlorine in the presence of ultraviolet light are hydrogen chloride and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trichloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dichloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetrachloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloromethane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tetrachloromethane is the final product of the reaction between methane and chlorine in the presence of ultraviolet light.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2010>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order of increasing boiling points of the following compounds <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>OH, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span> and C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>OH→C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>→C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>→C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span>→C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span>→C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>OH→C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>→C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>OH→C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Boiling point increases with increase in carbon atoms, among these, propanol is supposed to have the least boiling point because it has just 3 carbon atoms, but because of the presence of the -OH group, it's boiling point is higher than that of butane. So butane has the least boiling point, followed by propanol, then followed by heptane. <br/> Checking out their boiling points we have these: <br/> Butane: -1°C <br/> Propanol: 97°C <br/> Heptane: 98.42°C</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2010>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major uses of alkanes is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">as domestic and industrial fuels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in the hydrogenation of oils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in the textile industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in the production of plastics</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanes are primarily used as domestic and industrial fuels. They are the main constituents of natural gas and petroleum, which are widely used for heating and cooking in homes and as fuel in internal combustion engines.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2010>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The haloalkanes used in the dry-cleaning industries are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trichloromethane and tetrachloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloroethene and dichloroethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trichloroethene and tetrachloroethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloroethane and dichloroethene.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trichloromethane and tetra chloromethane are used in the dry-cleaning industries.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2010>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two hydrocarbons X and Y were treated with bromine water. X decolourized the solution and Y did not. Which class of compounds does Y belong?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Benzene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkynes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkenes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkanes.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Saturated organic compounds do not decolorise bromine water, hence Y is a saturated hydrocarbon, that is it is an alkane .</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2010>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The compound that is used as an anaesthetic is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CHCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>Cl</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CHCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, also known as Chloroform, is used as an anaesthetic. It was traditionally used in surgeries as an inhaled anesthetic, but it is not used for this purpose today because it can cause serious health problems.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}];
